**Replace `Layout/MainLayout.razor`:**
```razor
@inherits LayoutComponentBase
@inject ISyncService SyncService

<div class="app-container">
    <header class="app-header">
        <NavLink href="/" class="header-title" Match="NavLinkMatch.All">
            <span class="header-icon">🏗️</span>
            Site Inspector
        </NavLink>
        <div class="sync-status">
            @if (SyncService.IsSyncing)
            {
                <span class="sync-badge syncing">⟳ Syncing</span>
            }
            else if (!SyncService.IsOnline)
            {
                <span class="sync-badge offline">⚡ Offline</span>
            }
            else if (SyncService.PendingSyncCount > 0)
            {
                <button class="sync-badge pending" @onclick="SyncNow">
                    ↑ @SyncService.PendingSyncCount pending
                </button>
            }
            else
            {
                <span class="sync-badge online">✓ Online</span>
            }
        </div>
    </header>

    <main class="app-main">
        @Body
    </main>
</div>

@code {
    protected override void OnInitialized()
    {
        SyncService.OnSyncStateChanged += StateHasChanged;
    }

    private async Task SyncNow() => await SyncService.SyncAsync();
}
```

