using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Shared.Models;

namespace SiteInspector.Client.Services;

public class LocalStorageService : ILocalStorageService
{
    private readonly IJSRuntime _js;
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
        PropertyNameCaseInsensitive = true
    };

    public LocalStorageService(IJSRuntime js) => _js = js;

    public async Task InitializeAsync() =>
        await _js.InvokeVoidAsync("indexedDb.initialize");

    // Sites
    public async Task<List<ConstructionSite>> GetSitesAsync()
    {
        var items = await _js.InvokeAsync<JsonElement>("indexedDb.getAllItems", "sites");
        return Deserialize<List<ConstructionSite>>(items);
    }

    public async Task<ConstructionSite?> GetSiteAsync(string id)
    {
        var item = await _js.InvokeAsync<JsonElement?>("indexedDb.getItem", "sites", id);
        return item.HasValue ? Deserialize<ConstructionSite>(item.Value) : null;
    }

    public async Task SaveSiteAsync(ConstructionSite site)
    {
        site.UpdatedAt = DateTime.UtcNow;
        var obj = SerializeToElement(site);
        await _js.InvokeVoidAsync("indexedDb.putItem", "sites", obj);
    }

    public async Task DeleteSiteAsync(string id) =>
        await _js.InvokeVoidAsync("indexedDb.deleteItem", "sites", id);

    // Inspections
    public async Task<List<Inspection>> GetInspectionsAsync()
    {
        var items = await _js.InvokeAsync<JsonElement>("indexedDb.getAllItems", "inspections");
        return Deserialize<List<Inspection>>(items);
    }

    public async Task<List<Inspection>> GetInspectionsBySiteAsync(string siteId)
    {
        var items = await _js.InvokeAsync<JsonElement>("indexedDb.getItemsByIndex", "inspections", "siteId", siteId);
        return Deserialize<List<Inspection>>(items);
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var item = await _js.InvokeAsync<JsonElement?>("indexedDb.getItem", "inspections", id);
        return item.HasValue ? Deserialize<Inspection>(item.Value) : null;
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        inspection.UpdatedAt = DateTime.UtcNow;
        var obj = SerializeToElement(inspection);
        await _js.InvokeVoidAsync("indexedDb.putItem", "inspections", obj);
    }

    public async Task DeleteInspectionAsync(string id) =>
        await _js.InvokeVoidAsync("indexedDb.deleteItem", "inspections", id);

    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
    {
        var items = await _js.InvokeAsync<JsonElement>("indexedDb.getUnsyncedInspections");
        return Deserialize<List<Inspection>>(items);
    }

    private static T Deserialize<T>(JsonElement element) where T : new() =>
        JsonSerializer.Deserialize<T>(element.GetRawText(), JsonOptions) ?? new T();

    private static object SerializeToElement(object obj) =>
        JsonSerializer.Deserialize<JsonElement>(JsonSerializer.Serialize(obj, JsonOptions));
}
