using Microsoft.EntityFrameworkCore;
using SiteInspector.Server.Data;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddDbContext<InspectionDbContext>(options =>
    options.UseSqlite("Data Source=siteinspector.db"));

var app = builder.Build();

// Ensure DB is created
using (var scope = app.Services.CreateScope())
{
    var db = scope.ServiceProvider.GetRequiredService<InspectionDbContext>();
    db.Database.EnsureCreated();
}

app.UseBlazorFrameworkFiles();
app.UseStaticFiles();

app.MapPost("/api/sync", async (SiteInspector.Shared.Models.SyncPayload payload, InspectionDbContext db) =>
{
    var result = new SiteInspector.Shared.Models.SyncResult();

    try
    {
        foreach (var site in payload.Sites)
        {
            var existing = await db.Sites.FindAsync(site.Id);
            if (existing == null)
                db.Sites.Add(site);
            else
            {
                existing.Name = site.Name;
                existing.Address = site.Address;
                existing.UpdatedAt = site.UpdatedAt;
            }
            result.SitesSynced++;
        }

        foreach (var inspection in payload.Inspections)
        {
            var existing = await db.Inspections.FindAsync(inspection.Id);
            if (existing == null)
            {
                inspection.IsSynced = true;
                db.Inspections.Add(inspection);
            }
            else
            {
                if (inspection.UpdatedAt > existing.UpdatedAt)
                {
                    db.Entry(existing).CurrentValues.SetValues(inspection);
                    existing.IsSynced = true;
                }
            }
            result.InspectionsSynced++;
        }

        await db.SaveChangesAsync();
        result.Success = true;
    }
    catch (Exception ex)
    {
        result.Errors.Add(ex.Message);
    }

    return Results.Ok(result);
});

app.MapGet("/api/inspections", async (InspectionDbContext db) =>
    await db.Inspections.OrderByDescending(i => i.InspectionDate).Take(50).ToListAsync());

app.MapGet("/api/sites", async (InspectionDbContext db) =>
    await db.Sites.OrderBy(s => s.Name).ToListAsync());

app.MapFallbackToFile("index.html");

app.Run();
