**SyncService.cs:**
```csharp
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Shared.Models;

namespace SiteInspector.Client.Services;

public class SyncService : ISyncService, IAsyncDisposable
{
    private readonly ILocalStorageService _storage;
    private readonly HttpClient _http;
    private readonly IJSRuntime _js;
    private DotNetObjectReference<SyncService>? _dotNetRef;
    private Timer? _syncTimer;

    public bool IsOnline { get; private set; }
    public bool IsSyncing { get; private set; }
    public int PendingSyncCount { get; private set; }
    public event Action? OnSyncStateChanged;

    public SyncService(ILocalStorageService storage, HttpClient http, IJSRuntime js)
    {
        _storage = storage;
        _http = http;
        _js = js;
    }

    public async Task InitializeAsync()
    {
        IsOnline = await _js.InvokeAsync<bool>("connectivity.isOnline");
        _dotNetRef = DotNetObjectReference.Create(this);
        await _js.InvokeVoidAsync("connectivity.registerOnlineHandler", _dotNetRef);
        await UpdatePendingCountAsync();

        // Try sync every 30 seconds
        _syncTimer = new Timer(async _ =>
        {
            if (IsOnline && !IsSyncing && PendingSyncCount > 0)
                await SyncAsync();
        }, null, TimeSpan.FromSeconds(10), TimeSpan.FromSeconds(30));
    }

    [JSInvokable]
    public async Task OnConnectivityChanged(bool isOnline)
    {
        IsOnline = isOnline;
        OnSyncStateChanged?.Invoke();

        if (isOnline)
            await SyncAsync();
    }

    public async Task SyncAsync()
    {
        if (IsSyncing) return;

        try
        {
            IsSyncing = true;
            OnSyncStateChanged?.Invoke();

            var unsyncedInspections = await _storage.GetUnsyncedInspectionsAsync();
            var sites = await _storage.GetSitesAsync();

            if (unsyncedInspections.Count == 0 && sites.Count == 0) return;

            var payload = new SyncPayload
            {
                Sites = sites,
                Inspections = unsyncedInspections
            };

            var response = await _http.PostAsJsonAsync("api/sync", payload);

            if (response.IsSuccessStatusCode)
            {
                // Mark inspections as synced
                foreach (var inspection in unsyncedInspections)
                {
                    inspection.IsSynced = true;
                    await _storage.SaveInspectionAsync(inspection);
                }
            }
        }
        catch
        {
            // Sync failed — will retry on next timer tick or connectivity change
        }
        finally
        {
            IsSyncing = false;
            await UpdatePendingCountAsync();
            OnSyncStateChanged?.Invoke();
        }
    }

    private async Task UpdatePendingCountAsync()
    {
        try
        {
            var unsynced = await _storage.GetUnsyncedInspectionsAsync();
            PendingSyncCount = unsynced.Count;
        }
        catch
        {
            PendingSyncCount = 0;
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_syncTimer != null) await _syncTimer.DisposeAsync();
        _dotNetRef?.Dispose();
    }
}
