    [Parameter] public string Id { get; set; } = string.Empty;

    private Inspection? _inspection;
    private string _activeTab = "checklist";
    private Timer? _debounceTimer;

    protected override async Task OnInitializedAsync()
    {
        _inspection = await Storage.GetInspectionAsync(Id);
    }

    private async void SetResult(ChecklistItem item, CheckResult result)
    {
        item.Result = result;
        await SaveInspection();
        StateHasChanged();
    }

    private async void SetItemNote(ChecklistItem item, string note)
    {
        item.Notes = note;
        await SaveInspection();
    }

    private void SaveDebounced()
    {
        _debounceTimer?.Dispose();
        _debounceTimer = new Timer(async _ =>
        {
            await SaveInspection();
        }, null, 500, Timeout.Infinite);
    }

    private async Task SaveInspection()
    {
        if (_inspection == null) return;
        _inspection.IsSynced = false;
        await Storage.SaveInspectionAsync(_inspection);
    }

    private async Task CapturePhoto()
    {
        try
        {
            var result = await JS.InvokeAsync<PhotoResult?>("camera.capturePhoto", "photoInput");
            if (result != null && _inspection != null)
            {
                _inspection.Photos.Add(new InspectionPhoto
                {
                    FileName = result.FileName,
                    Base64Data = result.Base64Data,
                    ContentType = result.ContentType
                });
                await SaveInspection();
            }
        }
        catch
        {
            // Camera not available or cancelled
        }
    }

    private async Task SetCaption(InspectionPhoto photo, string caption)
    {
        photo.Caption = caption;
        await SaveInspection();
    }

    private async Task DeletePhoto(InspectionPhoto photo)
    {
        _inspection?.Photos.Remove(photo);
        await SaveInspection();
    }

    private async Task SaveAndReturn()
    {
        await SaveInspection();
        Nav.NavigateTo("/");
    }

    private class PhotoResult
    {
        public string FileName { get; set; } = string.Empty;
        public string Base64Data { get; set; } = string.Empty;
        public string ContentType { get; set; } = string.Empty;
    }
}
