```csharp
using Microsoft.EntityFrameworkCore;
using SiteInspector.Shared.Models;
using System.Text.Json;

namespace SiteInspector.Server.Data;

public class InspectionDbContext : DbContext
{
    public InspectionDbContext(DbContextOptions<InspectionDbContext> options) : base(options) { }

    public DbSet<ConstructionSite> Sites => Set<ConstructionSite>();
    public DbSet<Inspection> Inspections => Set<Inspection>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<ConstructionSite>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.Name).IsRequired().HasMaxLength(200);
            entity.Property(e => e.Address).HasMaxLength(500);
        });

        modelBuilder.Entity<Inspection>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.SiteId).IsRequired();
            entity.Property(e => e.Notes).HasColumnType("TEXT");

            // Store complex types as JSON
            entity.Property(e => e.ChecklistItems)
                .HasConversion(
                    v => JsonSerializer.Serialize(v, (JsonSerializerOptions?)null),
                    v => JsonSerializer.Deserialize<List<ChecklistItem>>(v, (JsonSerializerOptions?)null) ?? new())
                .HasColumnType("TEXT");

            entity.Property(e => e.Photos)
                .HasConversion(
                    v => JsonSerializer.Serialize(v, (JsonSerializerOptions?)null),
                    v => JsonSerializer.Deserialize<List<InspectionPhoto>>(v, (JsonSerializerOptions?)null) ?? new())
                .HasColumnType("TEXT");
        });
    }
}
