**Create `Pages/InspectionDetail.razor`:**
This is the main page inspectors use. It has tabs: Checklist, Notes, Photos.

```razor
@page "/inspection/{Id}"
@inject ILocalStorageService Storage
@inject NavigationManager Nav
@inject IJSRuntime JS

<PageTitle>Inspection</PageTitle>

@if (_inspection == null)
{
    <p class="loading">Loading...</p>
}
else
{
    <div class="inspection-detail">
        <div class="inspection-header">
            <h1>@_inspection.SiteName</h1>
            <p class="meta">
                👤 @_inspection.InspectorName · 📅 @_inspection.InspectionDate.ToLocalTime().ToString("MMM dd, yyyy")
            </p>
        </div>

        <div class="tab-bar">
            <button class="tab @(_activeTab == "checklist" ? "active" : "")" @onclick='() => _activeTab = "checklist"'>
                ✅ Checklist
            </button>
            <button class="tab @(_activeTab == "notes" ? "active" : "")" @onclick='() => _activeTab = "notes"'>
                📝 Notes
            </button>
            <button class="tab @(_activeTab == "photos" ? "active" : "")" @onclick='() => _activeTab = "photos"'>
                📷 Photos (@_inspection.Photos.Count)
            </button>
        </div>

        @if (_activeTab == "checklist")
        {
            <div class="checklist-container">
                @{ string? lastCategory = null; }
                @foreach (var item in _inspection.ChecklistItems)
                {
                    @if (item.Category != lastCategory)
                    {
                        lastCategory = item.Category;
                        <h3 class="category-header">@item.Category</h3>
                    }
                    <div class="checklist-item">
                        <span class="item-desc">@item.Description</span>
                        <div class="result-buttons">
                            <button class="result-btn pass @(item.Result == CheckResult.Pass ? "selected" : "")"
                                    @onclick="() => SetResult(item, CheckResult.Pass)">✓</button>
                            <button class="result-btn fail @(item.Result == CheckResult.Fail ? "selected" : "")"
                                    @onclick="() => SetResult(item, CheckResult.Fail)">✗</button>
                            <button class="result-btn na @(item.Result == CheckResult.NotApplicable ? "selected" : "")"
                                    @onclick="() => SetResult(item, CheckResult.NotApplicable)">N/A</button>
                        </div>
                        @if (item.Result == CheckResult.Fail)
                        {
                            <input class="item-note" placeholder="Add note for failed item..."
                                   value="@item.Notes"
                                   @onchange="(e) => SetItemNote(item, e.Value?.ToString() ?? string.Empty)" />
                        }
                    </div>
                }
            </div>
        }
        else if (_activeTab == "notes")
        {
            <div class="notes-container">
                <textarea class="notes-input" rows="10" placeholder="Add inspection notes..."
                          @bind="_inspection.Notes" @bind:event="oninput" @bind:after="SaveDebounced">
                </textarea>
            </div>
        }
        else if (_activeTab == "photos")
        {
            <div class="photos-container">
                <input type="file" id="photoInput" accept="image/*" capture="environment" style="display:none" />
                <button class="photo-btn" @onclick="CapturePhoto">📷 Take Photo</button>

                @if (_inspection.Photos.Count == 0)
                {
                    <p class="empty-photos">No photos attached yet.</p>
                }
                else
                {
                    <div class="photo-grid">
                        @foreach (var photo in _inspection.Photos)
                        {
                            <div class="photo-card">
                                <img src="data:@photo.ContentType;base64,@photo.Base64Data" alt="@photo.Caption" />
                                <input class="photo-caption" placeholder="Add caption..."
                                       value="@photo.Caption"
                                       @onchange="(e) => SetCaption(photo, e.Value?.ToString() ?? string.Empty)" />
                                <button class="photo-delete" @onclick="() => DeletePhoto(photo)">🗑 Remove</button>
                            </div>
                        }
                    </div>
                }
            </div>
        }

        <div class="bottom-actions">
            <div class="status-selector">
                <label>Status:</label>
                <select @bind="_inspection.Status" @bind:after="SaveInspection">
                    <option value="@InspectionStatus.InProgress">In Progress</option>
                    <option value="@InspectionStatus.Completed">Completed</option>
                    <option value="@InspectionStatus.RequiresFollowUp">Requires Follow-Up</option>
                </select>
            </div>
            <button class="save-btn" @onclick="SaveAndReturn">
                💾 Save & Close
            </button>
        </div>
    </div>
}

@code {
    [Parameter] public string Id { get; set; } = string.Empty;

    private Inspection? _inspection;
    private string _activeTab = "checklist";
    private Timer? _debounceTimer;

    protected override async Task OnInitializedAsync()
    {
        _inspection = await Storage.GetInspectionAsync(Id);
    }

    private async void SetResult(ChecklistItem item, CheckResult result)
    {
        item.Result = result;
        await SaveInspection();
        StateHasChanged();
    }

    private async void SetItemNote(ChecklistItem item, string note)
    {
        item.Notes = note;
        await SaveInspection();
    }

    private void SaveDebounced()
    {
        _debounceTimer?.Dispose();
        _debounceTimer = new Timer(async _ =>
        {
            await SaveInspection();
        }, null, 500, Timeout.Infinite);
    }

    private async Task SaveInspection()
    {
        if (_inspection == null) return;
        _inspection.IsSynced = false;
        await Storage.SaveInspectionAsync(_inspection);
    }

    private async Task CapturePhoto()
    {
        try
        {
            var result = await JS.InvokeAsync<PhotoResult?>("camera.capturePhoto", "photoInput");
            if (result != null && _inspection != null)
            {
                _inspection.Photos.Add(new InspectionPhoto
                {
                    FileName = result.FileName,
                    Base64Data = result.Base64Data,
                    ContentType = result.ContentType
                });
                await SaveInspection();
            }
        }
        catch
        {
            // Camera not available or cancelled
        }
    }

    private async Task SetCaption(InspectionPhoto photo, string caption)
    {
        photo.Caption = caption;
        await SaveInspection();
    }

    private async Task DeletePhoto(InspectionPhoto photo)
    {
        _inspection?.Photos.Remove(photo);
        await SaveInspection();
    }

    private async Task SaveAndReturn()
    {
        await SaveInspection();
        Nav.NavigateTo("/");
    }

    private class PhotoResult
    {
        public string FileName { get; set; } = string.Empty;
        public string Base64Data { get; set; } = string.Empty;
        public string ContentType { get; set; } = string.Empty;
    }
}
```

