app.MapPost("/api/sync", async (SiteInspector.Shared.Models.SyncPayload payload, InspectionDbContext db) =>
{
    var result = new SiteInspector.Shared.Models.SyncResult();

    try
    {
        foreach (var site in payload.Sites)
        {
            var existing = await db.Sites.FindAsync(site.Id);
            if (existing == null)
                db.Sites.Add(site);
            else
            {
                existing.Name = site.Name;
                existing.Address = site.Address;
                existing.UpdatedAt = site.UpdatedAt;
            }
            result.SitesSynced++;
        }

        foreach (var inspection in payload.Inspections)
        {
            var existing = await db.Inspections.FindAsync(inspection.Id);
            if (existing == null)
            {
                inspection.IsSynced = true;
                db.Inspections.Add(inspection);
            }
            else
            {
                if (inspection.UpdatedAt > existing.UpdatedAt)
                {
                    db.Entry(existing).CurrentValues.SetValues(inspection);
                    existing.IsSynced = true;
                }
            }
            result.InspectionsSynced++;
        }

        await db.SaveChangesAsync();
        result.Success = true;
    }
    catch (Exception ex)
    {
        result.Errors.Add(ex.Message);
    }

    return Results.Ok(result);
});

