@page "/"
@inject ILocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>Site Inspector</PageTitle>

<div class="home-page">
    <div class="quick-actions">
        <button class="action-btn primary" @onclick="StartNewInspection">
            ➕ New Inspection
        </button>
        <button class="action-btn" @onclick='() => Nav.NavigateTo("/sites")'>
            🏢 Manage Sites
        </button>
    </div>

    <h2>Recent Inspections</h2>

    @if (_loading)
    {
        <p class="loading">Loading...</p>
    }
    else if (_inspections.Count == 0)
    {
        <div class="empty-state">
            <p>No inspections yet.</p>
            <p>Tap <strong>New Inspection</strong> to get started.</p>
        </div>
    }
    else
    {
        <div class="inspection-list">
            @foreach (var inspection in _inspections)
            {
                <div class="inspection-card" @onclick='() => Nav.NavigateTo($"/inspection/{inspection.Id}")'>
                    <div class="card-header">
                        <span class="site-name">@inspection.SiteName</span>
                        <span class="status-badge @inspection.Status.ToString().ToLower()">
                            @FormatStatus(inspection.Status)
                        </span>
                    </div>
                    <div class="card-details">
                        <span>📅 @inspection.InspectionDate.ToLocalTime().ToString("MMM dd, yyyy h:mm tt")</span>
                        <span>👤 @inspection.InspectorName</span>
                    </div>
                    <div class="card-footer">
                        <span>✅ @inspection.ChecklistItems.Count(c => c.Result == CheckResult.Pass) / @inspection.ChecklistItems.Count items</span>
                        @if (!inspection.IsSynced)
                        {
                            <span class="not-synced">⬆ Not synced</span>
                        }
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    private List<Inspection> _inspections = new();
    private bool _loading = true;

    protected override async Task OnInitializedAsync()
    {
        var all = await Storage.GetInspectionsAsync();
        _inspections = all.OrderByDescending(i => i.InspectionDate).Take(20).ToList();
        _loading = false;
    }

    private void StartNewInspection() => Nav.NavigateTo("/inspection/new");

    private static string FormatStatus(InspectionStatus status) => status switch
    {
        InspectionStatus.InProgress => "In Progress",
        InspectionStatus.Completed => "Completed",
        InspectionStatus.RequiresFollowUp => "Follow Up",
        _ => status.ToString()
    };
}

.home-page { padding-bottom: 2rem; }

.quick-actions {
    display: flex;
    gap: 0.75rem;
    margin-bottom: 1.5rem;
}

.action-btn {
    flex: 1;
