@inject NavigationManager Nav

<PageTitle>New Inspection</PageTitle>

<div class="new-inspection">
    <h1>New Inspection</h1>

    <div class="form-group">
        <label>Inspector Name</label>
        <input @bind="_inspection.InspectorName" @bind:event="oninput" placeholder="Your name" class="form-input" />
    </div>

    <div class="form-group">
        <label>Construction Site</label>
        @if (_sites.Count == 0)
        {
            <p class="hint">No sites yet. <a href="/sites">Add a site first</a>.</p>
        }
        else
        {
            <select @bind="_selectedSiteId" class="form-input">
                <option value="">Select a site...</option>
                @foreach (var site in _sites)
                {
                    <option value="@site.Id">@site.Name — @site.Address</option>
                }
            </select>
        }
    </div>

    <div class="form-group">
        <label>Date & Time</label>
        <input type="datetime-local" @bind="_inspection.InspectionDate" class="form-input" />
    </div>

    <button class="start-btn" @onclick="StartInspection"
            disabled="@(string.IsNullOrWhiteSpace(_inspection.InspectorName) || string.IsNullOrWhiteSpace(_selectedSiteId))">
        Start Inspection ▶
    </button>
</div>

@code {
    private Inspection _inspection = new();
    private List<ConstructionSite> _sites = new();
    private string _selectedSiteId = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        _sites = (await Storage.GetSitesAsync()).OrderBy(s => s.Name).ToList();
        _inspection.InspectionDate = DateTime.Now;
    }

    private async Task StartInspection()
    {
        var site = _sites.First(s => s.Id == _selectedSiteId);
        _inspection.SiteId = site.Id;
        _inspection.SiteName = site.Name;
        _inspection.ChecklistItems = ChecklistTemplate.CreateDefault();
        _inspection.Status = InspectionStatus.InProgress;
        _inspection.IsSynced = false;

        await Storage.SaveInspectionAsync(_inspection);
        Nav.NavigateTo($"/inspection/{_inspection.Id}");
    }
}

