+        <h1>Construction Sites</h1>
+        <button class="add-btn" @onclick="ShowAddForm">+ Add Site</button>
+    </div>
+
+    @if (_showForm)
+    {
+        <div class="site-form">
+            <input @bind="_newSite.Name" @bind:event="oninput" placeholder="Site name" class="form-input" />
+            <input @bind="_newSite.Address" @bind:event="oninput" placeholder="Address" class="form-input" />
+            <div class="form-actions">
+                <button class="btn save" @onclick="SaveSite" disabled="@string.IsNullOrWhiteSpace(_newSite.Name)">
+                    Save
+                </button>
+                <button class="btn cancel" @onclick="CancelForm">Cancel</button>
+            </div>
+        </div>
+    }
+
+    @if (_sites.Count == 0 && !_loading)
+    {
+        <div class="empty-state">
+            <p>No sites added yet. Tap <strong>+ Add Site</strong> to create one.</p>
+        </div>
+    }
+    else
+    {
+        <div class="site-list">
+            @foreach (var site in _sites)
+            {
+                <div class="site-card">
+                    <div class="site-info">
+                        <span class="site-name">🏢 @site.Name</span>
+                        <span class="site-address">@site.Address</span>
+                    </div>
+                    <button class="delete-btn" @onclick="() => DeleteSite(site.Id)">🗑</button>
+                </div>
+            }
+        </div>
+    }
+</div>
+
+@code {
+    private List<ConstructionSite> _sites = new();
+    private ConstructionSite _newSite = new();
+    private bool _showForm;
+    private bool _loading = true;
+
+    protected override async Task OnInitializedAsync()
+    {
+        _sites = (await Storage.GetSitesAsync()).OrderBy(s => s.Name).ToList();
+        _loading = false;
+    }
+
+    private void ShowAddForm()
+    {
+        _newSite = new ConstructionSite();
+        _showForm = true;
+    }
+
+    private void CancelForm() => _showForm = false;
+
+    private async Task SaveSite()
+    {
+        await Storage.SaveSiteAsync(_newSite);
+        _sites = (await Storage.GetSitesAsync()).OrderBy(s => s.Name).ToList();
+        _showForm = false;
+    }
+
+    private async Task DeleteSite(string id)
+    {
+        await Storage.DeleteSiteAsync(id);
+        _sites = (await Storage.GetSitesAsync()).OrderBy(s => s.Name).ToList();
+    }
+}
+

